123→/**
124→ * Create a mock fetch function that returns a controlled Response.
125→ */
126→function createMockFetch(responseData: unknown, status = 200, ok = true) {
127→  return async () => {
128→    return {
129→      ok,
130→      status,
131→      json: async () => responseData,
132→      headers: {
133→        get: (name: string) => (name === 'content-type' ? 'application/json' : null),
134→      },
135→    } as Response;
136→  };
137→}
